#include <iostream>

int main() {
    int x = 1;
    int y = 2;
    auto recurse = [&](auto&& self, int n) mutable -> void {
        if (n == 0) return;
        x += y;
        y += 1;
        std::cout << x << "-" << y << " ";
        self(self, n - 1);
    };

    recurse(recurse, 4);
    return 0;
}

function formatUsers(users) {
  const result = [];
  for (let i = 0; i < users.length; i++) {
    let userString = '';
    if (users[i].isAdmin) {
      if (users[i].age) {
        userString = users[i].name + ' (Admin) - ' + users[i].age + ' years old';
      } else {
        userString = users[i].name + ' (Admin)';
      }
    } else {
      if (users[i].age) {
        userString = users[i].name + ' - ' + users[i].age + ' years old';
      } else {
        userString = users[i].name;
      }
    }
    result.push(userString);
  }
  return result;
}
